package fizeau

import (
	"context"
	"fmt"
	"io"
	"path/filepath"
	"strings"
	"sync"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/routehealth"
	"github.com/easel/fizeau/internal/serviceimpl"
	sessionusage "github.com/easel/fizeau/internal/session"
)

// FizeauService is the entire public Go surface of the fizeau module.
// See CONTRACT-003 for the full specification.
type FizeauService interface {
	Execute(ctx context.Context, req ServiceExecuteRequest) (<-chan ServiceEvent, error)
	TailSessionLog(ctx context.Context, sessionID string) (<-chan ServiceEvent, error)
	ListHarnesses(ctx context.Context) ([]HarnessInfo, error)
	ListProviders(ctx context.Context) ([]ProviderInfo, error)
	ListModels(ctx context.Context, filter ModelFilter) ([]ModelInfo, error)
	ListPolicies(ctx context.Context) ([]PolicyInfo, error)
	HealthCheck(ctx context.Context, health HealthTarget) error
	ResolveRoute(ctx context.Context, req RouteRequest) (*RouteDecision, error)
	RecordRouteAttempt(ctx context.Context, attempt RouteAttempt) error
	RouteStatus(ctx context.Context) (*RouteStatusReport, error)

	// Historical session-log projections. CONTRACT-003 owns these so CLI
	// subcommands such as log/replay/usage do not need to read the
	// internal session-log JSONL schema.
	UsageReport(ctx context.Context, opts UsageReportOptions) (*UsageReport, error)
	ListSessionLogs(ctx context.Context) ([]SessionLogEntry, error)
	WriteSessionLog(ctx context.Context, sessionID string, w io.Writer) error
	ReplaySession(ctx context.Context, sessionID string, w io.Writer) error
}

// ServiceConfig provides provider and routing data to the service without
// creating an import cycle from the root package into agent/config.
// Callers wrap their loaded *config.Config in a type that satisfies this interface.
type ServiceConfig interface {
	// ProviderNames returns provider names in stable order (default first).
	ProviderNames() []string
	// DefaultProviderName returns the name of the configured default provider.
	DefaultProviderName() string
	// Provider returns the raw config values for a named provider.
	Provider(name string) (ServiceProviderEntry, bool)
	// HealthCooldown returns the configured cooldown duration (0 = use default 30s).
	HealthCooldown() time.Duration
	// WorkDir is the base directory for file-backed health state.
	WorkDir() string
	// SessionLogDir returns the configured sessions directory.
	SessionLogDir() string
}

// ServiceProviderEntry carries the minimal provider data the service needs.
type ServiceProviderEntry struct {
	Type           string // "openai" | "openrouter" | "lmstudio" | "llama-server" | "ds4" | "omlx" | "lucebox" | "vllm" | "rapid-mlx" | "ollama" | "anthropic"
	BaseURL        string
	ServerInstance string
	Endpoints      []ServiceProviderEndpoint
	APIKey         string
	Headers        map[string]string
	Model          string // configured default model (may be empty)
	Billing        BillingModel
	// IncludeByDefault reports whether this provider participates in automatic
	// routing when the caller does not pin a provider.
	IncludeByDefault    bool
	IncludeByDefaultSet bool
	// ContextWindow is the configured provider-side context override.
	ContextWindow int
	// ConfigError marks this provider entry invalid while allowing the rest of
	// the service config to load. Invalid providers are reported in status
	// surfaces and excluded from routing.
	ConfigError string
	// DailyTokenBudget is the operator-configured per-UTC-day token budget
	// (request + response) for this provider. Zero means no local burn-rate
	// prediction; the provider's own quota signal still applies.
	DailyTokenBudget int
}

// ServiceProviderEndpoint is one configured provider serving endpoint.
type ServiceProviderEndpoint struct {
	Name           string
	BaseURL        string
	ServerInstance string
}

// ServiceOptions configures a FizeauService instance.
//
// seamOptions is embedded so production builds (no testseam tag) get an
// empty struct — making it a compile-time error to set seam fields without
// the build tag. Test builds inherit the four CONTRACT-003 seams
// (FakeProvider, PromptAssertionHook, CompactionAssertionHook,
// ToolWiringHook) automatically.
type ServiceOptions struct {
	seamOptions

	ConfigPath string    // optional override; default $XDG_CONFIG_HOME/fizeau/config.yaml
	Logger     io.Writer // optional; agent writes structured session logs internally regardless

	// ServiceConfig, when non-nil, supplies provider and routing data for
	// ListProviders and HealthCheck. Pass a value wrapping the loaded config.
	// When nil, those methods return an error.
	ServiceConfig ServiceConfig

	// QuotaRefreshDebounce is the minimum interval between live quota probes for
	// a primary subscription harness. Zero uses the service default.
	QuotaRefreshDebounce time.Duration
	// QuotaRefreshStartupWait bounds startup waiting when the durable quota
	// cache is missing, stale, or incomplete. Zero uses the service default.
	QuotaRefreshStartupWait time.Duration
	// QuotaRefreshInterval enables periodic refresh for long-running server
	// processes. Zero disables the timer; cache refresh still happens on startup
	// and service activity.
	QuotaRefreshInterval time.Duration
	// QuotaRefreshContext optionally cancels the periodic server refresh worker.
	// When nil, the worker uses context.Background().
	QuotaRefreshContext context.Context

	// CatalogProbeTimeout bounds live /v1/models discovery during routing.
	// Zero uses the service default of 2s.
	CatalogProbeTimeout time.Duration
	// CatalogReloadTimeout bounds stale-while-revalidate catalog reloads.
	// Zero uses the service default of 30s.
	CatalogReloadTimeout time.Duration

	// LocalCostUSDPer1kTokens is the operator-supplied electricity/operations
	// estimate for local endpoint providers under the embedded agent harness.
	// Zero means local endpoint cost is unknown.
	LocalCostUSDPer1kTokens float64
	// SubscriptionCostCurve optionally overrides the default subscription
	// effective-cost curve used by routing.
	SubscriptionCostCurve *SubscriptionCostCurve

	// SessionLogDir overrides the directory used by historical session-log
	// projections (UsageReport, ListSessionLogs, WriteSessionLog,
	// ReplaySession). Empty falls back to ServiceConfig.SessionLogDir().
	// Per-Execute requests still set their own
	// ServiceExecuteRequest.SessionLogDir.
	SessionLogDir string

	// StaleHarnessReaperGrace is the minimum age before a startup reaper may
	// terminate an owned subprocess record. Zero uses the default grace window.
	StaleHarnessReaperGrace time.Duration

	// HealthProbeInterval is the interval between background aliveness probes
	// for configured non-cloud providers. Zero uses the default (60s).
	HealthProbeInterval time.Duration
	// HealthSignalTTL is the maximum age of a probe result before it expires
	// for routing purposes. Zero uses the default (10 min).
	HealthSignalTTL time.Duration
	// PersistRouteHealth, when non-empty, is the file path where probe results
	// are persisted across processes so a fresh process skips redundant probing.
	PersistRouteHealth string
	// AlivenessProber, when non-nil, overrides the default TCP-connect prober
	// used during startup and periodic aliveness probing. Nil uses the default.
	AlivenessProber ProviderAlivenessProber
}

// SubscriptionCostCurve tunes effective subscription cost by quota utilization.
// Thresholds are percentages used, and multipliers are applied to the
// equivalent pay-per-token catalog rate.
type SubscriptionCostCurve struct {
	FreeUntilPercent   int
	LowUntilPercent    int
	MediumUntilPercent int
	LowMultiplier      float64
	MediumMultiplier   float64
	HighMultiplier     float64
}

// QuotaState is a live quota snapshot for a harness. Nil means not applicable.
type QuotaState struct {
	Windows    []harnesses.QuotaWindow `json:"windows"`
	CapturedAt time.Time               `json:"captured_at"`
	Fresh      bool                    `json:"fresh"`
	Source     string                  `json:"source,omitempty"`
	Status     string                  `json:"status,omitempty"` // ok|stale|unavailable|unauthenticated|unknown
	LastError  *StatusError            `json:"last_error,omitempty"`
}

// StatusError describes the most recent normalized status error for a harness,
// provider, or endpoint.
type StatusError struct {
	Type      string    // unavailable|unauthenticated|error
	Detail    string    // human-readable detail, safe for diagnostics
	Source    string    // config path, endpoint, cache path, or probe name
	Timestamp time.Time // zero when the source did not include a timestamp
}

// AccountStatus describes authentication/account state without exposing
// provider-specific native files to consumers.
type AccountStatus struct {
	Authenticated   bool
	Unauthenticated bool
	Email           string
	PlanType        string
	OrgName         string
	Source          string
	CapturedAt      time.Time
	Fresh           bool
	Detail          string
}

// UsageWindow describes normalized usage attribution over a time window.
// Empty token/cost totals mean the service has no historical usage source yet.
type UsageWindow struct {
	Name                string
	Source              string
	CapturedAt          time.Time
	Fresh               bool
	InputTokens         int
	OutputTokens        int
	TotalTokens         int
	CacheReadTokens     int
	CacheWriteTokens    int

package fizeau

import (
	"strings"
	"time"

	"github.com/easel/fizeau/internal/routehealth"
	"github.com/easel/fizeau/internal/routing"
)

const stickyRouteLeaseTTL = routehealth.DefaultLeaseTTL
const stickyRouteAffinityBonus = 250.0

func (s *service) routeLeaseStore() *routehealth.LeaseStore {
	if s.routeLeases == nil {
		s.routeLeases = routehealth.NewLeaseStore()
	}
	return s.routeLeases
}

func (s *service) routeUtilizationStore() *routehealth.UtilizationStore {
	if s.routeUtilization == nil {
		s.routeUtilization = routehealth.NewUtilizationStore()
	}
	return s.routeUtilization
}

func (s *service) applyStickyRouteLease(stickyKey string, decision *RouteDecision) {
	if s == nil || decision == nil || strings.TrimSpace(stickyKey) == "" {
		return
	}
	decision.Sticky.KeyPresent = true
	if decision.Harness != "fiz" || decision.Provider == "" {
		decision.Sticky.Assignment = "not_applicable"
		return
	}

	now := time.Now().UTC()
	store := s.routeLeaseStore()
	baseProvider, _, _ := splitEndpointProviderRef(decision.Provider)
	if baseProvider == "" {
		baseProvider = decision.Provider
	}
	if baseProvider == "" || decision.Model == "" {
		return
	}

	key := routehealth.NormalizeLeaseKey(stickyKey)
	selectedServerInstance := strings.TrimSpace(decision.ServerInstance)
	if selectedServerInstance == "" {
		selectedServerInstance = strings.TrimSpace(decision.Endpoint)
	}
	if selectedServerInstance == "" {
		_, selectedServerInstance, _ = splitEndpointProviderRef(decision.Provider)
	}
	if selectedServerInstance == "" {
		selectedServerInstance = decision.Provider
	}
	lease, ok := store.Live(now, key)
	if ok && lease.Endpoint == selectedServerInstance {
		decision.Sticky.Assignment = "reused"
		decision.Sticky.ServerInstance = selectedServerInstance
		decision.Sticky.Bonus = stickyRouteAffinityBonus
		decision.Sticky.Reason = "live sticky lease reused"
	} else if ok {
		decision.Sticky.Assignment = "moved"
		decision.Sticky.ServerInstance = selectedServerInstance
		decision.Sticky.Bonus = 0
		decision.Sticky.Reason = "sticky server instance lost to a stronger candidate"
	} else {
		decision.Sticky.Assignment = "acquired"
		decision.Sticky.ServerInstance = selectedServerInstance
		decision.Sticky.Bonus = 0
		if decision.Sticky.Reason == "" {
			decision.Sticky.Reason = "new sticky lease acquired"
		}
	}
	if selectedServerInstance == "" {
		decision.Sticky.Assignment = "none"
		return
	}
	store.Acquire(now, stickyRouteLeaseTTL, key, baseProvider, selectedServerInstance, decision.Model)
}

func (s *service) routeEndpointLoadsResolver(now time.Time) func(provider, endpoint, model string) (routing.EndpointLoad, bool) {
	if s == nil {
		return nil
	}
	leaseStore := s.routeLeaseStore()
	utilStore := s.routeUtilizationStore()
	return func(provider, endpoint, model string) (routing.EndpointLoad, bool) {
		leaseCounts := leaseStore.LeaseCounts(now, provider, model)
		loads := utilStore.EndpointLoads(provider, model, leaseCounts)
		load, ok := loads[endpoint]
		if !ok {
			if count, ok := leaseCounts[endpoint]; ok {
				return routing.EndpointLoad{
					LeaseCount:       count,
					NormalizedLoad:   float64(count),
					UtilizationFresh: false,
				}, true
			}
			return routing.EndpointLoad{}, false
		}
		return routing.EndpointLoad{
			LeaseCount:           load.LeaseCount,
			NormalizedLoad:       load.NormalizedLoad,
			UtilizationFresh:     load.UtilizationFresh,
			UtilizationSaturated: load.UtilizationSaturated,
		}, true
	}
}

func (s *service) routeStickyServerInstanceResolver(now time.Time) func(stickyKey string) (string, bool) {
	if s == nil {
		return nil
	}
	store := s.routeLeaseStore()
	return func(stickyKey string) (string, bool) {
		if strings.TrimSpace(stickyKey) == "" {
			return "", false
		}
		lease, ok := store.Live(now, routehealth.NormalizeLeaseKey(stickyKey))
		if !ok {
			return "", false
		}
		if lease.Endpoint == "" {
			return "", false
		}
		return lease.Endpoint, true
	}
}

package fizeau

import (
	"context"
	"sync"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
)

// refreshScheduler owns the single service-wide async refresh cadence
// across every registered QuotaHarness and AccountHarness. It is the
// replacement for the per-harness Refresh*Async helpers described in
// CONTRACT-004 / plan-2026-05-14-harness-interface-refactor.md Step 4.
//
// One debounced ticker is scheduled per registered QuotaHarness at
// QuotaFreshness()/2 cadence. An independent ticker is scheduled per
// registered AccountHarness only when its AccountFreshness() differs
// from the harness's QuotaFreshness() — when the cadences match, the
// QuotaHarness ticker is sufficient for callers that want to drive
// account refreshes alongside quota.
//
// The scheduler does not enforce single-flight itself. RefreshQuota /
// RefreshAccount are required by CONTRACT-004 to be single-flight per
// harness instance (via the harness's cache lock); the scheduler relies
// on that contract. Cache-freshness deduplication, however, is the
// scheduler's responsibility: it reads QuotaStatus before each refresh
// and skips ticks where CapturedAt is within QuotaFreshness() of now,
// so that RefreshQuota itself can probe unconditionally per
// CONTRACT-004 invariant #4.
//
// Pre-migration (Steps 5–8 of the refactor not yet landed), the
// concrete Runner types do not yet implement QuotaHarness or
// AccountHarness. Type assertions fail and the scheduler registers
// nothing for those harnesses; they continue to use their existing
// Refresh*Async helpers until each harness's e-step deletes them.
type refreshScheduler struct {
	lookup func(name string) harnesses.Harness
	names  []string
	clock  schedulerClock

	// tickNotify, when non-nil, receives the harness name after each
	// tick is fully processed (refresh attempted or skipped). Tests
	// use this to synchronize on tick completion; production leaves
	// it nil.
	tickNotify chan<- string

	mu     sync.Mutex
	ctx    context.Context
	cancel context.CancelFunc
	wg     sync.WaitGroup
}

// schedulerClock is the time abstraction the refresh scheduler uses.
// The production implementation wraps time.Now / time.NewTicker; tests
// inject a controllable fake clock to drive cadence deterministically.
type schedulerClock interface {
	Now() time.Time
	NewTicker(d time.Duration) schedulerTicker
}

// schedulerTicker is a minimal time.Ticker abstraction.
type schedulerTicker interface {
	C() <-chan time.Time
	Stop()
}

// realClock is the wall-clock implementation of schedulerClock.
type realClock struct{}

func (realClock) Now() time.Time { return time.Now() }

func (realClock) NewTicker(d time.Duration) schedulerTicker {
	return &realTicker{t: time.NewTicker(d)}
}

type realTicker struct{ t *time.Ticker }

func (r *realTicker) C() <-chan time.Time { return r.t.C }
func (r *realTicker) Stop()               { r.t.Stop() }

// newRefreshScheduler constructs (but does not start) a scheduler over
// the harness names supplied. lookup returns the registered Harness
// instance for each name; a nil result is tolerated and means the name
// is registered but has no live instance, in which case the scheduler
// registers nothing for that name. clock defaults to realClock when
// nil.
func newRefreshScheduler(lookup func(string) harnesses.Harness, names []string, clock schedulerClock) *refreshScheduler {
	if clock == nil {
		clock = realClock{}
	}
	return &refreshScheduler{
		lookup: lookup,
		names:  append([]string(nil), names...),
		clock:  clock,
	}
}

// Start launches the scheduler. For every registered harness, it
// type-asserts to QuotaHarness and AccountHarness independently. For
// each capability the harness satisfies, it:
//
//  1. Reads the current cached status. When the status reports
//     QuotaUnavailable (cache-cold), the scheduler fires one
//     immediate refresh.
//  2. Starts a debounced ticker at Freshness/2 cadence that drives
//     subsequent refreshes.
//
// Start is not safe to call concurrently; concurrent Start panics.
// Call Stop before re-starting.
func (s *refreshScheduler) Start(parent context.Context) {
	s.mu.Lock()
	if s.cancel != nil {
		s.mu.Unlock()
		panic("refreshScheduler: Start called twice without intervening Stop")
	}
	s.ctx, s.cancel = context.WithCancel(parent)
	s.mu.Unlock()

	now := s.clock.Now()
	for _, name := range s.names {
		h := s.lookup(name)
		if h == nil {
			continue
		}
		qh, isQuota := h.(harnesses.QuotaHarness)
		ah, isAccount := h.(harnesses.AccountHarness)

		if isQuota {
			s.startQuotaTicker(name, qh, now)
		}
		if isAccount {
			// Only start a separate account ticker when account
			// freshness differs from quota freshness. When they
			// match, the quota cadence already covers the cache
			// lifetime account refresh would observe; harnesses
			// that want account-aligned refresh can implement it
			// inside RefreshQuota. See CONTRACT-004 / Step 4.
			if !isQuota || ah.AccountFreshness() != qh.QuotaFreshness() {
				s.startAccountTicker(name, ah, now)
			}
		}
	}
}

// Stop cancels the scheduler context and waits for every ticker
// goroutine to exit. Safe to call on a never-started scheduler (no-op).
func (s *refreshScheduler) Stop() {
	s.mu.Lock()
	cancel := s.cancel
	s.cancel = nil
	s.mu.Unlock()
	if cancel == nil {
		return
	}
	cancel()
	s.wg.Wait()
}

// startQuotaTicker fires the cache-cold kickoff (if applicable) and
// launches the per-harness debounced ticker.
func (s *refreshScheduler) startQuotaTicker(name string, qh harnesses.QuotaHarness, now time.Time) {
	interval := qh.QuotaFreshness() / 2
	if interval <= 0 {
		// Misconfigured harness: a non-positive freshness disables
		// scheduling — the scheduler refuses to busy-loop. Surfaced
		// as a CONTRACT-004 violation by the conformance suite.
		return
	}

	// Cache-cold startup kickoff. Per
	// primary-harness-capability-baseline.md and AC #6, the
	// scheduler fires one RefreshQuota immediately when the
	// cached state is QuotaUnavailable.
	if status, err := qh.QuotaStatus(s.ctx, now); err == nil && status.State == harnesses.QuotaUnavailable {
		s.wg.Add(1)
		go func() {
			defer s.wg.Done()
			_, _ = qh.RefreshQuota(s.ctx)
		}()
	}

	ticker := s.clock.NewTicker(interval)
	s.wg.Add(1)
	go func() {
		defer s.wg.Done()
		defer ticker.Stop()
		for {
			select {
			case <-s.ctx.Done():
				return
			case <-ticker.C():
				s.maybeRefreshQuota(name, qh)
			}
		}
	}()
}

// maybeRefreshQuota implements the per-tick decision. On cache-cold
// (QuotaUnavailable) it always refreshes. Otherwise it skips when
// CapturedAt is within QuotaFreshness() of now (cache-freshness dedup
// is the scheduler's job, not RefreshQuota's). All other tick
// outcomes result in a RefreshQuota call.
func (s *refreshScheduler) maybeRefreshQuota(name string, qh harnesses.QuotaHarness) {
	defer s.notifyTick(name)

	now := s.clock.Now()
	status, err := qh.QuotaStatus(s.ctx, now)
	if err != nil {
		return
	}

	if status.State == harnesses.QuotaUnavailable {
		_, _ = qh.RefreshQuota(s.ctx)
		return
	}

	if !status.CapturedAt.IsZero() && now.Sub(status.CapturedAt) < qh.QuotaFreshness() {
		return
	}

	_, _ = qh.RefreshQuota(s.ctx)
}

// startAccountTicker is the AccountHarness analogue of
// startQuotaTicker. Cache-cold is detected via a zero CapturedAt
// because AccountSnapshot has no explicit "unavailable" state value.
func (s *refreshScheduler) startAccountTicker(name string, ah harnesses.AccountHarness, now time.Time) {
	interval := ah.AccountFreshness() / 2
	if interval <= 0 {
		return
	}

	if snap, err := ah.AccountStatus(s.ctx, now); err == nil && snap.CapturedAt.IsZero() {
		s.wg.Add(1)
		go func() {
			defer s.wg.Done()
			_, _ = ah.RefreshAccount(s.ctx)
		}()
	}

	ticker := s.clock.NewTicker(interval)
	s.wg.Add(1)
	go func() {
		defer s.wg.Done()
		defer ticker.Stop()
		for {
			select {
			case <-s.ctx.Done():
				return
			case <-ticker.C():
				s.maybeRefreshAccount(name, ah)
			}
		}
	}()
}

// maybeRefreshAccount mirrors maybeRefreshQuota for AccountHarness.
func (s *refreshScheduler) maybeRefreshAccount(name string, ah harnesses.AccountHarness) {
	defer s.notifyTick(name)

package fizeau

import (
	"context"
	"sort"
	"strings"
	"time"

	"github.com/easel/fizeau/internal/modelsnapshot"
	"github.com/easel/fizeau/internal/routehealth"
	"github.com/easel/fizeau/internal/serverinstance"
)

// RouteStatus returns live routing state for configured providers/models.
// It is the operator dashboard view: cooldowns, recent decisions, and
// per-candidate health. Distinct from per-request ResolveRoute.
func (s *service) RouteStatus(ctx context.Context) (*RouteStatusReport, error) {
	s.ensurePrimaryQuotaRefresh(ctx, quotaRefreshAsync)
	report := &RouteStatusReport{
		GeneratedAt: time.Now(),
	}
	// ADR-006 §5: populate routing-quality over a recent window
	// (RouteStatusRoutingQualityWindow) regardless of whether a route
	// catalog is configured — the metric reflects Execute traffic, not
	// configured routes.
	if s != nil && s.routingQuality != nil {
		recent := s.routingQuality.snapshotRecent(RouteStatusRoutingQualityWindow, time.Time{})
		report.RoutingQuality = computeRoutingQualityMetricsFromRecords(recent)
	}
	if s == nil || s.opts.ServiceConfig == nil {
		return report, nil
	}

	cat := serviceRoutingCatalog()
	_, snapshot := s.buildRoutingInputsWithCatalog(ctx, cat, modelsnapshot.RefreshBackground)
	cooldown := s.routeAttemptTTL()
	activeAttempts := s.activeRouteAttempts(report.GeneratedAt, cooldown)
	successRate, latencyMS := s.routeMetricSignals(report.GeneratedAt, cooldown)
	report.SnapshotCapturedAt = snapshot.AsOf
	report.Routes = s.routeStatusEntriesFromSnapshot(snapshot, activeAttempts, successRate, latencyMS, cooldown)
	return report, nil
}

func (s *service) routeStatusEntriesFromSnapshot(snapshot modelsnapshot.ModelSnapshot, activeAttempts []routehealth.Record, successRate, latencyMS map[string]float64, cooldown time.Duration) []RouteStatusEntry {
	if len(snapshot.Models) == 0 {
		return nil
	}
	grouped := make(map[string][]modelsnapshot.KnownModel)
	for _, row := range snapshot.Models {
		if harness := strings.TrimSpace(row.Harness); harness != "" && harness != "fiz" {
			continue
		}
		if s.opts.ServiceConfig != nil {
			if _, ok := s.opts.ServiceConfig.Provider(row.Provider); !ok {
				continue
			}
		}
		model := strings.TrimSpace(row.ID)
		if model == "" {
			continue
		}
		grouped[model] = append(grouped[model], row)
	}
	if len(grouped) == 0 {
		return nil
	}
	keys := make([]string, 0, len(grouped))
	for model := range grouped {
		keys = append(keys, model)
	}
	sort.Strings(keys)

	entries := make([]RouteStatusEntry, 0, len(keys))
	for _, model := range keys {
		rows := grouped[model]
		sort.Slice(rows, func(i, j int) bool {
			if rows[i].Provider != rows[j].Provider {
				return rows[i].Provider < rows[j].Provider
			}
			if rows[i].EndpointName != rows[j].EndpointName {
				return rows[i].EndpointName < rows[j].EndpointName
			}
			if rows[i].EndpointBaseURL != rows[j].EndpointBaseURL {
				return rows[i].EndpointBaseURL < rows[j].EndpointBaseURL
			}
			if rows[i].ServerInstance != rows[j].ServerInstance {
				return rows[i].ServerInstance < rows[j].ServerInstance
			}
			return rows[i].ID < rows[j].ID
		})
		entry := RouteStatusEntry{Model: model, Strategy: "auto"}
		if cached, ok := s.lookupRouteDecision(model); ok {
			entry.LastDecision = cached.decision
			entry.LastDecisionAt = cached.at
			entry.SelectedEndpoint = cached.decision.Endpoint
			entry.SelectedServerInstance = cached.decision.ServerInstance
			entry.Sticky = cached.decision.Sticky
		}
		entry.Candidates = make([]RouteCandidateStatus, 0, len(rows))
		for i, row := range rows {
			provider := strings.TrimSpace(row.Provider)
			endpoint := strings.TrimSpace(row.EndpointName)
			serverID := serverinstance.Normalize(row.EndpointBaseURL, row.ServerInstance)
			candidate := RouteCandidateStatus{
				Provider:                      provider,
				Endpoint:                      endpoint,
				Model:                         model,
				ServerInstance:                serverID,
				Billing:                       row.Billing,
				ActualCashSpend:               row.ActualCashSpend,
				EffectiveCost:                 row.EffectiveCost,
				EffectiveCostSource:           row.EffectiveCostSource,
				Priority:                      len(rows) - i,
				Healthy:                       true,
				SourceStatus:                  string(row.Status),
				AutoRoutable:                  row.AutoRoutable,
				ExactPinOnly:                  row.ExactPinOnly,
				ExclusionReason:               row.ExclusionReason,
				Power:                         row.Power,
				ContextLength:                 row.ContextWindow,
				CostInputPerMTok:              row.CostInputPerM,
				CostOutputPerMTok:             row.CostOutputPerM,
				RecentLatencyMS:               float64(row.RecentP50Latency.Milliseconds()),
				ProviderReliabilityRate:       routeStatusMetricValue(successRate, provider, endpoint, model),
				QuotaRemaining:                row.QuotaRemaining,
				SnapshotCapturedAt:            snapshot.AsOf,
				HealthFreshnessAt:             row.HealthFreshnessAt.UTC(),
				HealthFreshnessSource:         row.HealthFreshnessSource,
				QuotaFreshnessAt:              row.QuotaFreshnessAt.UTC(),
				QuotaFreshnessSource:          row.QuotaFreshnessSource,
				ModelDiscoveryFreshnessAt:     row.DiscoveredAt.UTC(),
				ModelDiscoveryFreshnessSource: string(row.DiscoveredVia),
			}
			if attemptCooldown := routeAttemptCandidateCooldown(activeAttempts, provider, endpoint, model, cooldown); attemptCooldown != nil {
				candidate.Cooldown = attemptCooldown
			}
			if candidate.Cooldown != nil {
				candidate.Healthy = false
			}
			if candidate.RecentLatencyMS == 0 {
				candidate.RecentLatencyMS = routeStatusMetricValue(latencyMS, provider, endpoint, model)
			}
			entry.Candidates = append(entry.Candidates, candidate)
		}
		entries = append(entries, entry)
	}
	return entries
}

func routeStatusMetricValue(values map[string]float64, provider, endpoint, model string) float64 {
	if len(values) == 0 {
		return 0
	}
	key := routeStatusMetricKey(provider, endpoint, model)
	if value, ok := values[key]; ok {
		return value
	}
	if endpoint != "" {
		if value, ok := values[routeStatusMetricKey(provider, "", model)]; ok {
			return value
		}
	}
	return 0
}

func routeStatusMetricKey(provider, endpoint, model string) string {
	return routehealth.ProviderModelKey(routehealth.Key{
		Provider: provider,
		Endpoint: endpoint,
		Model:    model,
	})
}

func routeAttemptCandidateCooldown(records []routehealth.Record, providerName, endpointName, model string, cooldown time.Duration) *CooldownState {
	internal := routehealth.CandidateCooldown(records, providerName, endpointName, model, cooldown)
	if internal == nil {
		return nil
	}
	return &CooldownState{
		Reason:      internal.Reason,
		Until:       internal.Until,
		FailCount:   internal.FailCount,
		LastError:   internal.LastError,
		LastAttempt: internal.LastAttempt,
	}
}

// cacheRouteDecision stores a ResolveRoute result keyed by routeKey.
// Called by ResolveRoute after a successful resolution.
func (s *service) cacheRouteDecision(routeKey string, dec *RouteDecision) {
	if routeKey == "" || dec == nil {
		return
	}
	s.lastDecisionMu.Lock()
	defer s.lastDecisionMu.Unlock()
	if s.lastDecisionCache == nil {
		s.lastDecisionCache = make(map[string]lastDecisionEntry)
	}
	s.lastDecisionCache[routeKey] = lastDecisionEntry{
		decision: dec,
		at:       time.Now(),
	}
}

// lookupRouteDecision retrieves a cached decision for routeKey.
func (s *service) lookupRouteDecision(routeKey string) (lastDecisionEntry, bool) {
	s.lastDecisionMu.RLock()
	defer s.lastDecisionMu.RUnlock()
	if s.lastDecisionCache == nil {
		return lastDecisionEntry{}, false
	}
	e, ok := s.lastDecisionCache[routeKey]
	return e, ok
}

