package routehealth

import (
	"sort"
	"strings"
	"sync"
	"time"
)

// DefaultLeaseTTL bounds how long an in-process sticky route lease may live
// without being refreshed.
const DefaultLeaseTTL = 5 * time.Minute

// LeaseKey identifies one sticky lease scope.
type LeaseKey struct {
	StickyKey string
}

// Lease describes one sticky endpoint assignment.
type Lease struct {
	Key         LeaseKey
	Provider    string
	Endpoint    string
	Model       string
	AcquiredAt  time.Time
	RefreshedAt time.Time
	ExpiresAt   time.Time
}

// LeaseInvalidation records why a lease was removed.
type LeaseInvalidation struct {
	Key        LeaseKey
	Provider   string
	Endpoint   string
	Model      string
	Reason     string
	RecordedAt time.Time
}

// LeaseStore owns in-process sticky route assignments. It is safe for
// concurrent use.
type LeaseStore struct {
	mu            sync.Mutex
	leases        map[LeaseKey]Lease
	invalidations map[LeaseKey]LeaseInvalidation
}

// NewLeaseStore returns an empty lease store.
func NewLeaseStore() *LeaseStore {
	return &LeaseStore{
		leases:        make(map[LeaseKey]Lease),
		invalidations: make(map[LeaseKey]LeaseInvalidation),
	}
}

// NormalizeLeaseKey trims whitespace from the sticky key.
func NormalizeLeaseKey(stickyKey string) LeaseKey {
	return LeaseKey{StickyKey: strings.TrimSpace(stickyKey)}
}

// Live returns the current lease for key when it has not expired.
func (s *LeaseStore) Live(now time.Time, key LeaseKey) (Lease, bool) {
	if s == nil {
		return Lease{}, false
	}
	now = normalizeLeaseNow(now)

	s.mu.Lock()
	defer s.mu.Unlock()
	s.expireLocked(now)
	lease, ok := s.leases[key]
	if !ok {
		return Lease{}, false
	}
	return lease, true
}

// Acquire stores or refreshes a lease for key.
func (s *LeaseStore) Acquire(now time.Time, ttl time.Duration, key LeaseKey, provider, endpoint, model string) Lease {
	if s == nil {
		return Lease{}
	}
	now = normalizeLeaseNow(now)
	if ttl <= 0 {
		ttl = DefaultLeaseTTL
	}
	key = NormalizeLeaseKey(key.StickyKey)
	provider = strings.TrimSpace(provider)
	endpoint = strings.TrimSpace(endpoint)
	model = strings.TrimSpace(model)

	s.mu.Lock()
	defer s.mu.Unlock()
	s.expireLocked(now)

	lease := Lease{
		Key:         key,
		Provider:    provider,
		Endpoint:    endpoint,
		Model:       model,
		AcquiredAt:  now,
		RefreshedAt: now,
		ExpiresAt:   now.Add(ttl),
	}
	if existing, ok := s.leases[key]; ok {
		if existing.Provider == provider && existing.Endpoint == endpoint && existing.Model == model {
			lease.AcquiredAt = existing.AcquiredAt
		}
	}
	s.leases[key] = lease
	delete(s.invalidations, key)
	return lease
}

// Invalidate removes the lease for key and records the reason.
func (s *LeaseStore) Invalidate(now time.Time, key LeaseKey, reason string) (LeaseInvalidation, bool) {
	if s == nil {
		return LeaseInvalidation{}, false
	}
	now = normalizeLeaseNow(now)
	key = NormalizeLeaseKey(key.StickyKey)

	s.mu.Lock()
	defer s.mu.Unlock()
	s.expireLocked(now)
	lease, ok := s.leases[key]
	if !ok {
		return LeaseInvalidation{}, false
	}
	delete(s.leases, key)
	invalidation := LeaseInvalidation{
		Key:        key,
		Provider:   lease.Provider,
		Endpoint:   lease.Endpoint,
		Model:      lease.Model,
		Reason:     strings.TrimSpace(reason),
		RecordedAt: now,
	}
	s.invalidations[key] = invalidation
	return invalidation, true
}

// InvalidateEndpoint removes every lease for the provider/model scope that
// points at the named endpoint and records the supplied reason.
func (s *LeaseStore) InvalidateEndpoint(now time.Time, provider, endpoint, model, reason string) []LeaseInvalidation {
	if s == nil {
		return nil
	}
	now = normalizeLeaseNow(now)
	provider = strings.TrimSpace(provider)
	endpoint = strings.TrimSpace(endpoint)
	model = strings.TrimSpace(model)

	s.mu.Lock()
	defer s.mu.Unlock()
	s.expireLocked(now)
	if len(s.leases) == 0 {
		return nil
	}
	var out []LeaseInvalidation
	for key, lease := range s.leases {
		if provider != "" && lease.Provider != provider {
			continue
		}
		if endpoint != "" && lease.Endpoint != endpoint {
			continue
		}
		if model != "" && lease.Model != model {
			continue
		}
		delete(s.leases, key)
		invalidation := LeaseInvalidation{
			Key:        key,
			Provider:   lease.Provider,
			Endpoint:   lease.Endpoint,
			Model:      lease.Model,
			Reason:     strings.TrimSpace(reason),
			RecordedAt: now,
		}
		s.invalidations[key] = invalidation
		out = append(out, invalidation)
	}
	return out
}

// LiveByScope returns the live leases for provider/model, ordered by sticky
// key for deterministic tests.
func (s *LeaseStore) LiveByScope(now time.Time, provider, model string) []Lease {
	if s == nil {
		return nil
	}
	now = normalizeLeaseNow(now)
	provider = strings.TrimSpace(provider)
	model = strings.TrimSpace(model)

	s.mu.Lock()
	defer s.mu.Unlock()
	s.expireLocked(now)
	if len(s.leases) == 0 {
		return nil
	}
	out := make([]Lease, 0, len(s.leases))
	for _, lease := range s.leases {
		if provider != "" && lease.Provider != provider {
			continue
		}
		if model != "" && lease.Model != model {
			continue
		}
		out = append(out, lease)
	}
	sort.Slice(out, func(i, j int) bool {
		if out[i].Endpoint != out[j].Endpoint {
			return out[i].Endpoint < out[j].Endpoint
		}
		return out[i].Key.StickyKey < out[j].Key.StickyKey
	})
	return out
}

// LeaseCounts returns the live lease count per endpoint for provider/model.
func (s *LeaseStore) LeaseCounts(now time.Time, provider, model string) map[string]int {
	leases := s.LiveByScope(now, provider, model)
	if len(leases) == 0 {
		return nil
	}
	counts := make(map[string]int, len(leases))
	for _, lease := range leases {
		counts[lease.Endpoint]++
	}
	return counts
}

// LastInvalidation returns the most recent invalidation recorded for key.
func (s *LeaseStore) LastInvalidation(key LeaseKey) (LeaseInvalidation, bool) {
	if s == nil {
		return LeaseInvalidation{}, false
	}
	key = NormalizeLeaseKey(key.StickyKey)

	s.mu.Lock()
	defer s.mu.Unlock()
	invalidation, ok := s.invalidations[key]
	return invalidation, ok
}

func (s *LeaseStore) expireLocked(now time.Time) {
	for key, lease := range s.leases {
		if lease.ExpiresAt.IsZero() || lease.ExpiresAt.After(now) {
			continue
		}
		delete(s.leases, key)
		s.invalidations[key] = LeaseInvalidation{
			Key:        key,
			Provider:   lease.Provider,
			Endpoint:   lease.Endpoint,
			Model:      lease.Model,
			Reason:     "expired",
			RecordedAt: now,
		}

package routehealth

import (
	"fmt"
	"strings"
	"sync"
	"time"

	"github.com/easel/fizeau/internal/routing"
)

// DefaultCooldown is the process-local route-attempt TTL used when service
// configuration does not provide a health cooldown.
const DefaultCooldown = 30 * time.Second

// Attempt records availability feedback for one routed attempt.
type Attempt struct {
	Harness   string
	Provider  string
	Model     string
	Endpoint  string
	Status    string
	Reason    string
	Error     string
	Duration  time.Duration
	Timestamp time.Time
}

// Key is the normalized route-attempt identity.
type Key struct {
	Harness  string
	Provider string
	Model    string
	Endpoint string
}

// Record is an active route-attempt failure.
type Record struct {
	Key        Key
	Status     string
	Reason     string
	Error      string
	Duration   time.Duration
	RecordedAt time.Time
}

type metricRecord struct {
	attempts      int
	successes     int
	totalDuration time.Duration
	recordedAt    time.Time
}

// Store owns process-local route-attempt failure feedback and reliability
// metrics. It is safe for concurrent use.
type Store struct {
	mu       sync.RWMutex
	failures map[Key]Record
	metrics  map[Key]metricRecord
}

// NewStore returns an empty route-health store.
func NewStore() *Store {
	return &Store{
		failures: make(map[Key]Record),
		metrics:  make(map[Key]metricRecord),
	}
}

// RecordAttempt records availability feedback. Success clears matching active
// failures; non-success records an active failure and updates metrics.
func (s *Store) RecordAttempt(attempt Attempt) error {
	key := NormalizeKey(attempt)
	if key.Harness == "" && key.Provider == "" {
		return fmt.Errorf("route attempt requires harness or provider")
	}
	status := strings.ToLower(strings.TrimSpace(attempt.Status))
	if status == "" {
		return fmt.Errorf("route attempt status is required")
	}
	recordedAt := attempt.Timestamp
	if recordedAt.IsZero() {
		recordedAt = time.Now()
	}
	recordedAt = recordedAt.UTC()

	s.mu.Lock()
	defer s.mu.Unlock()
	if s.failures == nil {
		s.failures = make(map[Key]Record)
	}
	if s.metrics == nil {
		s.metrics = make(map[Key]metricRecord)
	}
	s.recordMetricLocked(key, Succeeded(status), attempt.Duration, recordedAt)

	if Succeeded(status) {
		s.clearFailuresLocked(key)
		return nil
	}

	s.failures[key] = Record{
		Key:        key,
		Status:     status,
		Reason:     strings.TrimSpace(attempt.Reason),
		Error:      strings.TrimSpace(attempt.Error),
		Duration:   attempt.Duration,
		RecordedAt: recordedAt,
	}
	return nil
}

func (s *Store) recordMetricLocked(key Key, success bool, duration time.Duration, recordedAt time.Time) {
	record := s.metrics[key]
	record.attempts++
	if success {
		record.successes++
	}
	if duration > 0 {
		record.totalDuration += duration
	}
	record.recordedAt = recordedAt
	s.metrics[key] = record
}

// NormalizeKey returns the normalized route-attempt key for attempt.
func NormalizeKey(attempt Attempt) Key {
	return Key{
		Harness:  strings.TrimSpace(attempt.Harness),
		Provider: strings.TrimSpace(attempt.Provider),
		Model:    strings.TrimSpace(attempt.Model),
		Endpoint: strings.TrimSpace(attempt.Endpoint),
	}
}

// Succeeded reports whether status is a success spelling.
func Succeeded(status string) bool {
	switch status {
	case "success", "ok", "succeeded":
		return true
	default:
		return false
	}
}

func (s *Store) clearFailuresLocked(key Key) {
	for existing := range s.failures {
		if KeysMatch(existing, key) {
			delete(s.failures, existing)
		}
	}
}

// KeysMatch reports whether existing satisfies every non-empty query field.
func KeysMatch(existing, query Key) bool {
	if query.Harness != "" && existing.Harness != query.Harness {
		return false
	}
	if query.Provider != "" && existing.Provider != query.Provider {
		return false
	}
	if query.Model != "" && existing.Model != query.Model {
		return false
	}
	if query.Endpoint != "" && existing.Endpoint != query.Endpoint {
		return false
	}
	return true
}

// ActiveAttempts returns active failure records and removes expired records
// from the store.
func (s *Store) ActiveAttempts(now time.Time, ttl time.Duration) []Record {
	if s == nil {
		return nil
	}
	if ttl <= 0 {
		ttl = DefaultCooldown
	}
	if now.IsZero() {
		now = time.Now()
	}
	now = now.UTC()

	s.mu.Lock()
	defer s.mu.Unlock()
	if len(s.failures) == 0 {
		return nil
	}
	out := make([]Record, 0, len(s.failures))
	for key, record := range s.failures {
		if !record.RecordedAt.Add(ttl).After(now) {
			delete(s.failures, key)
			continue
		}
		out = append(out, record)
	}
	return out
}

// MetricSignals returns provider/model success-rate and latency maps suitable
// for routing inputs.
func (s *Store) MetricSignals(now time.Time, ttl time.Duration) (map[string]float64, map[string]float64) {
	if s == nil {
		return nil, nil
	}
	if ttl <= 0 {
		ttl = DefaultCooldown
	}
	if now.IsZero() {
		now = time.Now()
	}
	now = now.UTC()

	s.mu.RLock()
	defer s.mu.RUnlock()
	if len(s.metrics) == 0 {
		return nil, nil
	}
	successRate := make(map[string]float64, len(s.metrics))
	latencyMS := make(map[string]float64, len(s.metrics))
	for key, record := range s.metrics {
		if record.attempts <= 0 {
			continue
		}
		if !record.recordedAt.IsZero() && !record.recordedAt.Add(ttl).After(now) {
			continue
		}
		metricKey := ProviderModelKey(key)
		successRate[metricKey] = float64(record.successes) / float64(record.attempts)
		if record.totalDuration > 0 {
			latencyMS[metricKey] = float64(record.totalDuration.Milliseconds()) / float64(record.attempts)
		}
	}
	return successRate, latencyMS
}

// ProviderModelKey returns the routing provider/model metric key for key.
func ProviderModelKey(key Key) string {
	return routing.ProviderModelKey(key.Provider, key.Endpoint, key.Model)
}

package routehealth

import (
	"errors"
	"sort"
	"strings"
	"time"

	"github.com/easel/fizeau/internal/routing"
)

// PowerRequest is the routing-power subset used to compute the effective
// power policy for a public RouteRequest.
type PowerRequest struct {
	Policy   string
	Model    string
	MinPower int
	MaxPower int
}

// PowerPolicy is the internal representation of the effective power-policy
// evidence that the service surfaces publicly.
type PowerPolicy struct {
	PolicyName string
	MinPower   int
	MaxPower   int
}

// PolicySpec is the narrow policy surface PowerPolicy needs from the catalog.
type PolicySpec struct {
	Name     string
	MinPower int
	MaxPower int
}

// PolicyLookup resolves one named policy.
type PolicyLookup func(name string) (PolicySpec, bool)

// EffectivePowerPolicy merges caller-supplied bounds with the matched policy.
func EffectivePowerPolicy(req PowerRequest, lookup PolicyLookup) PowerPolicy {
	policy := PowerPolicy{
		PolicyName: req.Policy,
		MinPower:   req.MinPower,
		MaxPower:   req.MaxPower,
	}
	if strings.TrimSpace(req.Policy) == "" || lookup == nil {
		return policy
	}
	spec, ok := lookup(req.Policy)
	if !ok {
		return policy
	}
	policy.PolicyName = spec.Name
	if spec.MinPower > 0 && (policy.MinPower == 0 || spec.MinPower > policy.MinPower) {
		policy.MinPower = spec.MinPower
	}
	if spec.MaxPower > 0 && (policy.MaxPower == 0 || spec.MaxPower < policy.MaxPower) {
		policy.MaxPower = spec.MaxPower
	}
	return policy
}

// PowerBoundsForRequest returns the bounds the routing engine should enforce.
func PowerBoundsForRequest(req PowerRequest, policy PowerPolicy) (int, int) {
	if strings.TrimSpace(req.Model) != "" {
		return req.MinPower, req.MaxPower
	}
	return policy.MinPower, policy.MaxPower
}

// FilterReason maps the internal typed filter reason to the public string
// surface without reparsing human-readable reason text.
func FilterReason(candidate routing.Candidate) string {
	if candidate.Eligible {
		return ""
	}
	return string(candidate.FilterReason)
}

// EscalatePolicyLadder walks routing.PolicyEscalationLadder when a lower tier
// produced only rejected candidates. The caller supplies the escalation gate so
// root-owned errors can stay in the root package without an import cycle.
func EscalatePolicyLadder(req routing.Request, in routing.Inputs, origErr error, displayPolicy string, shouldEscalate func(error) bool) (bool, *routing.Decision, error) {
	if origErr == nil || strings.TrimSpace(req.Policy) == "" {
		return false, nil, nil
	}
	if shouldEscalate != nil && !shouldEscalate(origErr) {
		return false, nil, nil
	}
	startIdx := -1
	for i, policy := range routing.PolicyEscalationLadder {
		if policy == req.Policy {
			startIdx = i
			break
		}
	}
	if startIdx < 0 {
		return false, nil, nil
	}
	for i := startIdx + 1; i < len(routing.PolicyEscalationLadder); i++ {
		probe := req
		probe.Policy = routing.PolicyEscalationLadder[i]
		dec, err := routing.Resolve(probe, in)
		if err == nil && dec != nil && dec.Harness != "" {
			return true, dec, nil
		}
	}
	starting := displayPolicy
	if starting == "" {
		starting = req.Policy
	}
	return true, nil, &routing.ErrNoLiveProvider{
		PromptTokens:   req.EstimatedPromptTokens,
		RequiresTools:  req.RequiresTools,
		StartingPolicy: starting,
		MinPower:       req.MinPower,
		MaxPower:       req.MaxPower,
		AllowLocal:     req.AllowLocal,
	}
}

// ShouldEscalateOnError reports whether a routing-engine error is eligible for
// policy-ladder escalation.
func ShouldEscalateOnError(err error) bool {
	var modelErr *routing.ErrHarnessModelIncompatible
	if errors.As(err, &modelErr) {
		return false
	}
	var pinErr *routing.ErrUnsatisfiablePin
	if errors.As(err, &pinErr) {
		return false
	}
	var policyErr *routing.ErrPolicyRequirementUnsatisfied
	if errors.As(err, &policyErr) {
		return false
	}
	return true
}

// Cooldown is the internal cooldown evidence shape used by adapters in the
// root package.
type Cooldown struct {
	Reason      string
	Until       time.Time
	FailCount   int
	LastError   string
	LastAttempt time.Time
}

// CooldownTTL applies the default route-attempt TTL when the configured
// cooldown is unset.
func CooldownTTL(configured time.Duration) time.Duration {
	if configured <= 0 {
		return DefaultCooldown
	}
	return configured
}

// CooldownFromRecord projects one active failure record into cooldown state.
func CooldownFromRecord(record Record, ttl time.Duration) Cooldown {
	ttl = CooldownTTL(ttl)
	reason := record.Reason
	if reason == "" {
		reason = "route_attempt_failure"
	}
	return Cooldown{
		Reason:      reason,
		Until:       record.RecordedAt.Add(ttl),
		FailCount:   1,
		LastError:   record.Error,
		LastAttempt: record.RecordedAt,
	}
}

// CandidateCooldown finds the newest active failure matching the candidate
// scope and returns its cooldown evidence.
func CandidateCooldown(records []Record, providerName, endpointName, model string, ttl time.Duration) *Cooldown {
	var newest *Record
	for i := range records {
		record := &records[i]
		if record.Key.Provider == "" {
			continue
		}
		recordProvider := record.Key.Provider
		recordEndpoint := record.Key.Endpoint
		if base, endpoint, ok := splitProviderRef(recordProvider); ok {
			recordProvider = base
			if recordEndpoint == "" {
				recordEndpoint = endpoint
			}
		}
		if providerName != "" && recordProvider != providerName {
			continue
		}
		if endpointName != "" && recordEndpoint != "" && recordEndpoint != endpointName {
			continue
		}
		if record.Key.Model != "" && model != "" && record.Key.Model != model {
			continue
		}
		if newest == nil || record.RecordedAt.After(newest.RecordedAt) {
			newest = record
		}
	}
	if newest == nil {
		return nil
	}
	cooldown := CooldownFromRecord(*newest, ttl)
	return &cooldown
}

// ApplyAttemptCooldowns projects active attempt failures into routing inputs.
func ApplyAttemptCooldowns(in *routing.Inputs, records []Record, ttl time.Duration) {
	if in == nil || len(records) == 0 {
		return
	}
	ttl = CooldownTTL(ttl)
	if in.ProviderCooldowns == nil {
		in.ProviderCooldowns = make(map[string]time.Time)
	}
	if in.CooldownDuration <= 0 {
		in.CooldownDuration = ttl
	}
	for _, record := range records {
		if record.Key.Provider != "" {
			existing, ok := in.ProviderCooldowns[record.Key.Provider]
			if !ok || record.RecordedAt.After(existing) {
				in.ProviderCooldowns[record.Key.Provider] = record.RecordedAt
			}
			if IsDispatchabilityFailure(record.Error) {
				if in.ProviderUnreachable == nil {
					in.ProviderUnreachable = make(map[string]time.Time)
				}
				existing, ok := in.ProviderUnreachable[record.Key.Provider]
				if !ok || record.RecordedAt.After(existing) {
					in.ProviderUnreachable[record.Key.Provider] = record.RecordedAt
				}
			}
		}
		if record.Key.Provider == "" && record.Key.Harness != "" {
			for i := range in.Harnesses {
				if in.Harnesses[i].Name == record.Key.Harness {
					in.Harnesses[i].InCooldown = true
				}
			}
		}
	}
}

